import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"宋庆龄故居","description":"","frontmatter":{},"headers":[],"relativePath":"history/soong-ching-ling-residence.md","filePath":"history/soong-ching-ling-residence.md","lastUpdated":1784773307000}'),n={name:"history/soong-ching-ling-residence.md"};function d(o,t,i,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="宋庆龄故居" tabindex="-1">宋庆龄故居 <a class="header-anchor" href="#宋庆龄故居" aria-label="Permalink to &quot;宋庆龄故居&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1583977393611-885b3e5cc701?w=1200" alt="宋庆龄故居"></p><blockquote><p>&quot;国之瑰宝，二十世纪中国最伟大的女性之一。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>宋庆龄故居位于北京市西城区后海北沿46号，是一座典型的北京四合院。宋庆龄女士从1963年至1981年在此居住，度过了人生的最后18年。故居原为清代醇亲王府花园的一部分，环境优美，现已成为&quot;宋庆龄同志故居&quot;，展示着这位伟大女性的生平事迹。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:30（周二至周日），周一闭馆</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">20元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-1.5小时</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2/8号线鼓楼大街站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区后海北沿46号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="醇亲王府花园" tabindex="-1">醇亲王府花园 <a class="header-anchor" href="#醇亲王府花园" aria-label="Permalink to &quot;醇亲王府花园&quot;">​</a></h3><p>宋庆龄故居原为清代醇亲王府的花园。醇亲王是光绪帝的父亲、宣统帝的祖父，王府建于清代，花园精美典雅。</p><h3 id="宋庆龄晚年" tabindex="-1">宋庆龄晚年 <a class="header-anchor" href="#宋庆龄晚年" aria-label="Permalink to &quot;宋庆龄晚年&quot;">​</a></h3><p>1963年，宋庆龄女士迁入此院，在此居住直至1981年逝世。这18年间，她继续从事中国福利事业和儿童工作，接待了众多国内外宾客。</p><h4 id="晚年成就" tabindex="-1">晚年成就 <a class="header-anchor" href="#晚年成就" aria-label="Permalink to &quot;晚年成就&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">事件</th></tr></thead><tbody><tr><td style="text-align:left;">1963年</td><td style="text-align:left;">迁入后海北沿46号</td></tr><tr><td style="text-align:left;">1966年</td><td style="text-align:left;">创立中国福利会</td></tr><tr><td style="text-align:left;">1981年</td><td style="text-align:left;">逝世于此，享年88岁</td></tr></tbody></table><h2 id="故居布局" tabindex="-1">故居布局 <a class="header-anchor" href="#故居布局" aria-label="Permalink to &quot;故居布局&quot;">​</a></h2><h3 id="四合院结构" tabindex="-1">四合院结构 <a class="header-anchor" href="#四合院结构" aria-label="Permalink to &quot;四合院结构&quot;">​</a></h3><p>宋庆龄故居是一座典型的北京四合院，分为前院、中院和后院，环境清幽，花木扶疏。</p><h4 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">建筑</th><th style="text-align:left;">功能</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大门</strong></td><td style="text-align:left;">入口</td><td style="text-align:left;">传统朱漆大门</td></tr><tr><td style="text-align:left;"><strong>前院</strong></td><td style="text-align:left;">接待区</td><td style="text-align:left;">客厅、接待室</td></tr><tr><td style="text-align:left;"><strong>中院</strong></td><td style="text-align:left;">生活区</td><td style="text-align:left;">宋庆龄居室、书房</td></tr><tr><td style="text-align:left;"><strong>后院</strong></td><td style="text-align:left;">花园</td><td style="text-align:left;">百年海棠、月季</td></tr><tr><td style="text-align:left;"><strong>东西厢房</strong></td><td style="text-align:left;">展览室</td><td style="text-align:left;">生平事迹展</td></tr></tbody></table><h3 id="主要展室" tabindex="-1">主要展室 <a class="header-anchor" href="#主要展室" aria-label="Permalink to &quot;主要展室&quot;">​</a></h3><h4 id="宋庆龄居室" tabindex="-1">宋庆龄居室 <a class="header-anchor" href="#宋庆龄居室" aria-label="Permalink to &quot;宋庆龄居室&quot;">​</a></h4><p>宋庆龄的居室简朴而典雅，保留了她生前的原貌。</p><ul><li><strong>卧室</strong>：简朴的卧室，摆放着她生前使用的家具</li><li><strong>书房</strong>：她工作和学习的地方，藏书丰富</li><li><strong>会客室</strong>：会见国内外宾客的场所</li></ul><h4 id="生平事迹展" tabindex="-1">生平事迹展 <a class="header-anchor" href="#生平事迹展" aria-label="Permalink to &quot;生平事迹展&quot;">​</a></h4><p>故居内设有宋庆龄生平事迹展，展示了这位伟大女性的一生。</p><h2 id="珍贵文物" tabindex="-1">珍贵文物 <a class="header-anchor" href="#珍贵文物" aria-label="Permalink to &quot;珍贵文物&quot;">​</a></h2><h3 id="生活用品" tabindex="-1">生活用品 <a class="header-anchor" href="#生活用品" aria-label="Permalink to &quot;生活用品&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">文物</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>家具</strong></td><td style="text-align:left;">生前使用的木质家具</td></tr><tr><td style="text-align:left;"><strong>衣物</strong></td><td style="text-align:left;">各时期穿着的旗袍、外套</td></tr><tr><td style="text-align:left;"><strong>书信</strong></td><td style="text-align:left;">与孙中山、毛泽东等人的往来书信</td></tr><tr><td style="text-align:left;"><strong>照片</strong></td><td style="text-align:left;">各历史时期的照片</td></tr><tr><td style="text-align:left;"><strong>奖章</strong></td><td style="text-align:left;">获得的荣誉奖章和证书</td></tr></tbody></table><h3 id="特殊展品" tabindex="-1">特殊展品 <a class="header-anchor" href="#特殊展品" aria-label="Permalink to &quot;特殊展品&quot;">​</a></h3><ul><li><strong>孙中山遗物</strong>：与孙中山先生的合影、遗物</li><li><strong>儿童礼物</strong>：各国儿童赠送的礼物</li><li><strong>外交礼品</strong>：外国友人赠送的礼品</li></ul><h2 id="花园景观" tabindex="-1">花园景观 <a class="header-anchor" href="#花园景观" aria-label="Permalink to &quot;花园景观&quot;">​</a></h2><h3 id="百年海棠" tabindex="-1">百年海棠 <a class="header-anchor" href="#百年海棠" aria-label="Permalink to &quot;百年海棠&quot;">​</a></h3><p>故居花园内有两棵百年西府海棠，是宋庆龄生前最喜爱的花木。每年春天，海棠花开，繁花似锦。</p><h3 id="月季花" tabindex="-1">月季花 <a class="header-anchor" href="#月季花" aria-label="Permalink to &quot;月季花&quot;">​</a></h3><p>宋庆龄生前喜爱月季，花园内种植了各种月季，四季常开。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约1小时）</strong>：</p><p>入口 → 前院（客厅） → 中院（宋庆龄居室、书房） → 后院（花园、百年海棠） → 东西厢房（生平展） → 出口</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前预约</strong>：建议提前在官网或电话预约</li><li><strong>最佳时间</strong>：春季海棠花开时最美</li><li><strong>拍照位置</strong>：百年海棠前、书房前都是绝佳拍照点</li><li><strong>讲解服务</strong>：可以租用讲解器，了解更多历史</li><li><strong>周边游览</strong>：参观完后可以到什刹海、恭王府游览</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">2/8号线鼓楼大街站G口，步行约10分钟</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">5、60、82、107、124路鼓楼站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;宋庆龄故居&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">步行1分钟</td><td style="text-align:left;">老北京水乡</td></tr><tr><td style="text-align:left;">恭王府</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">清代王府</td></tr><tr><td style="text-align:left;">钟鼓楼</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">老北京地标</td></tr><tr><td style="text-align:left;">南锣鼓巷</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">网红胡同</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>宋庆龄是中国近现代史上杰出的女性政治家、社会活动家，被尊称为&quot;国之瑰宝&quot;。她的一生是为中国革命和建设事业奋斗的一生，她的精神永远激励着后人。</p><p>&quot;永远和党在一起&quot;，这是宋庆龄先生的遗愿，也是她一生的真实写照。</p><hr><p><strong>📍 地址</strong>：北京市西城区后海北沿46号 <strong>🚇 地铁</strong>：2/8号线鼓楼大街站G口 <strong>📞 电话</strong>：010-62042295 <strong>🌐 官网</strong>：<a href="http://www.sqlgj.org" target="_blank" rel="noreferrer">www.sqlgj.org</a></p><p><strong>💡 Tips</strong>：宋庆龄故居与什刹海相邻，可以安排在同一天游览。春季海棠花开时，景色最美。</p>',51)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
